      image: '/images/blog/blog-14.jpg',
      featured: true,
      read_time: '12 min de leitura',
      date: '2026-03-12',
      tags: ['Choque Elétrico', 'Segurança', 'NR-10', 'Primeiros Socorros', 'Prevenção']
